transform_js:
var W=100,H=100;
var maxT=rawData.rows.reduce(function(m,d){return Math.max(m,Number(d.groupA)+Number(d.groupB));},0);
var nodes=rawData.rows.map(function(d){
  var a=Number(d.groupA),b=Number(d.groupB),t=a+b;
  var rA=t?a/t:0.5;
  var size=3.0+Math.sqrt(t/maxT)*9;
  var tx=5+90*rA;
  return {name:d.word,a:a,b:b,total:t,ratioA:rA,ratioB:t?b/t:0.5,size:size,targetX:tx,x:50,y:50,vx:0,vy:0};
});

/* Phase 1: Greedy circle packing into a tight blob at the center */
nodes.sort(function(a,b){return b.size-a.size;});
var placed=[];
function hits(cx,cy,r,skip){
  for(var i=0;i<placed.length;i++){
    if(i===skip) continue;
    var p=placed[i],dx=cx-p.x,dy=cy-p.y,md=r+p.size+0.15;
    if(dx*dx+dy*dy<md*md) return true;
  }
  return false;
}
for(var i=0;i<nodes.length;i++){
  var n=nodes[i];
  if(i===0){n.x=50;n.y=50;placed.push(n);continue;}
  /* Try placing tangent to each existing circle, pick position closest to center */
  var bestD=1e9,bx=50,by=50;
  for(var j=0;j<placed.length;j++){
    var p=placed[j];
    var touchD=p.size+n.size+0.15;
    for(var ang=0;ang<360;ang+=6){
      var rad=ang*Math.PI/180;
      var cx=p.x+Math.cos(rad)*touchD;
      var cy=p.y+Math.sin(rad)*touchD;
      if(cx-n.size<0||cx+n.size>W||cy-n.size<0||cy+n.size>H) continue;
      if(!hits(cx,cy,n.size,j)){
        var dd=Math.sqrt((cx-50)*(cx-50)+(cy-50)*(cy-50));
        if(dd<bestD){bestD=dd;bx=cx;by=cy;}
      }
    }
  }
  n.x=bx;n.y=by;
  placed.push(n);
}

/* Phase 2: Force simulation to shift toward target X while keeping tight packing */
for(var iter=0;iter<300;iter++){
  for(var i=0;i<nodes.length;i++){
    var n=nodes[i];
    n.vx+=(n.targetX-n.x)*0.03;
    n.vy+=(50-n.y)*0.01;
  }
  for(var i=0;i<nodes.length;i++){
    for(var j=i+1;j<nodes.length;j++){
      var a2=nodes[i],b2=nodes[j];
      var dx=b2.x-a2.x,dy=b2.y-a2.y;
      var dist=Math.sqrt(dx*dx+dy*dy)||0.01;
      var minD=a2.size+b2.size+0.15;
      if(dist<minD){
        var f=(minD-dist)/dist*0.5;
        a2.vx-=dx*f;a2.vy-=dy*f;
        b2.vx+=dx*f;b2.vy+=dy*f;
      }
    }
  }
  for(var i=0;i<nodes.length;i++){
    var n=nodes[i];
    n.x+=n.vx;n.y+=n.vy;
    n.vx*=0.6;n.vy*=0.6;
    n.x=Math.max(n.size,Math.min(W-n.size,n.x));
    n.y=Math.max(n.size,Math.min(H-n.size,n.y));
  }
}
transformedData=nodes.map(function(d){return [d.x,d.y,d.size,d.ratioA,d.ratioB,d.name,d.a,d.b];});

echarts_js:
var CA='#6b96c4';var CB='#e2856e';
var TXT='#2c3e50';
option={
  tooltip:{trigger:'item',formatter:function(p){var d=p.data;return '<b>'+d[5]+'</b><br/><span style="color:'+CA+'">●</span> 営業部: '+d[6]+'<br/><span style="color:'+CB+'">●</span> 開発部: '+d[7];}},
  grid:{left:0,right:0,top:45,bottom:0},
  xAxis:{type:'value',min:0,max:100,show:false},
  yAxis:{type:'value',min:0,max:100,show:false},
  graphic:[
    {type:'text',left:'8%',top:20,style:{text:'← 営業部がよく使う',fill:CA,fontSize:15,fontWeight:'bold'}},
    {type:'text',right:'8%',top:20,style:{text:'開発部がよく使う →',fill:CB,fontSize:15,fontWeight:'bold'}}
  ],
  series:[{
    type:'custom',
    renderItem:function(params,api){
      var cW=params.coordSys.width,cH=params.coordSys.height;
      var px=api.coord([api.value(0),api.value(1)]);
      var x=px[0],y=px[1];
      var refLen=Math.min(cW,cH);
      var r=api.value(2)/100*refLen;
      var rA=api.value(3),rB=api.value(4);
      var name=api.value(5),valA=api.value(6),valB=api.value(7);
      var s0=-Math.PI/2;
      var s1=s0+rB*Math.PI*2;
      var s2=s1+rA*Math.PI*2;
      var fs=Math.max(10,Math.min(16,r*0.45));
      var fsSub=Math.max(8,fs-3);
      return {
        type:'group',
        children:[
          {type:'sector',shape:{cx:x,cy:y,r:r,r0:0,startAngle:s0,endAngle:s1},style:{fill:CB,stroke:'#fff',lineWidth:1.5}},
          {type:'sector',shape:{cx:x,cy:y,r:r,r0:0,startAngle:s1,endAngle:s2},style:{fill:CA,stroke:'#fff',lineWidth:1.5}},
          {type:'text',style:{text:name,x:x,y:y-fsSub*0.4,textAlign:'center',textVerticalAlign:'middle',fill:TXT,fontSize:fs,fontWeight:'bold',fontFamily:'sans-serif'}},
          {type:'text',style:{text:valA+' - '+valB,x:x,y:y+fs*0.5,textAlign:'center',textVerticalAlign:'middle',fill:TXT,fontSize:fsSub,fontFamily:'sans-serif',opacity:0.7}}
        ]
      };
    },
    data:transformedData,
    animation:true,animationDuration:1200,animationEasing:'cubicOut'
  }]
};
